export function getLang() {
  try {
    return localStorage.getItem('sh_lang') || 'en'
  } catch {
    return 'en'
  }
}

export function setLang(lang) {
  try {
    localStorage.setItem('sh_lang', lang)
    window.location.reload()
  } catch {
    window.location.reload()
  }
}

/** Shallow-merge current language over English so missing keys fall back cleanly. */
const __i18nMissingKeysLogged = new Set()

export function getActiveTranslations() {
  const lang = getLang()
  const base = t.en || {}
  const override = t[lang] || {}
  const merged = { ...base, ...override }
  if (typeof import.meta !== 'undefined' && import.meta.env?.DEV) {
    return new Proxy(merged, {
      get(target, prop, receiver) {
        if (typeof prop === 'symbol') return Reflect.get(target, prop, receiver)
        const val = Reflect.get(target, prop, receiver)
        if (val === undefined && typeof prop === 'string') {
          const sig = `${lang}::${prop}`
          if (!__i18nMissingKeysLogged.has(sig)) {
            __i18nMissingKeysLogged.add(sig)
            console.warn(`[i18n] Missing key "${prop}" after en fallback (lang=${lang})`)
          }
        }
        return val
      },
    })
  }
  return merged
}

/** Replace `{name}` placeholders in translated templates (insights, alerts, etc.). */
export function interpolate(template, vars = {}) {
  if (template == null || template === '') return ''
  return String(template).replace(/\{(\w+)\}/g, (_, key) =>
    vars[key] !== undefined && vars[key] !== null ? String(vars[key]) : `{${key}}`
  )
}

export function useT() {
  return getActiveTranslations()
}

